SELECT item_id as itemId, gym_id as gymId, item_category as itemCategory, item_count as itemCount, item_name as itemName, item_date as itemDate, item_price as itemPrice, item_status as itemStatus, item_expiry_date as itemExpiryDate FROM "h_item" WHERE gym_id = #{gymId}
AND item_name LIKE CONCAT('%', #{pager.searchKeyword}, '%')
ORDER BY item_count DESC ORDER BY item_price DESC ORDER BY item_id DESC
LIMIT #{pager.pageSize} OFFSET #{pager.offset}

SELECT DISTINCT item_name as itemName
FROM "h_item"
WHERE gym_id = #{gymId}

SELECT item_id as itemId, gym_id as gymId, item_category as itemCategory, item_count as itemCount, item_name as itemName, item_date as itemDate, item_price as itemPrice, item_status as itemStatus, item_expiry_date as itemExpiryDate FROM "h_item" WHERE gym_id = #{gymId}
AND item_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY item_id DESC
